class Solution:
    def isPalindrome(self, x: int) -> bool:
        if x < 0:
            return False

        test: List[int] = []       
        while x != 0:
            test.append(x % 10)
            x //= 10

        left = 0
        right = len(test) - 1
        while left < right:
            if test[left] != test[right]:
                return False
            left += 1
            right -= 1

        return True
